const AWS = require('aws-sdk');
const s3 = new AWS.S3({ region: 'your-region' });
const documentProcessor = require('./document-processor');

exports.handler = async (event) => {
  try {
    const bucketName = event.Records[0].s3.bucket.name;
    const fileName = event.Records[0].s3.object.key;

    // Validate the file type
    if (!['txt', 'pdf', 'docx'].includes(fileName.split('.').pop())) {
      console.log(`Invalid file type: ${fileName}`);
      return { statusCode: 400 };
    }

    // Read the file from S3
    const params = { Bucket: bucketName, Key: fileName };
    const data = await s3.getObject(params).promise();

    // Process the document
    const result = await documentProcessor.processDocument(data.Body.toString());

    // Save results to another S3 location
    const outputBucketName = 'output-bucket';
    const outputFileName = `${fileName.split('.')[0]}-processed.${fileName.split('.').pop()}`;
    const outputParams = { Bucket: outputBucketName, Key: outputFileName, Body: result };
    await s3.putObject(outputParams).promise();

    console.log(`Processed file saved to ${outputBucketName}/${outputFileName}`);
  } catch (error) {
    console.error(error);
    throw error;
  }

  return { statusCode: 200 };
};